import { Injectable, InternalServerErrorException } from '@nestjs/common';
import { HttpService } from '@nestjs/axios';
import { lastValueFrom } from 'rxjs';

@Injectable()
export class KybService {
  constructor(private readonly httpService: HttpService) {}

  async verifyBusiness(registrationNumber: string, companyType: string) {
    const apiKey = process.env.PREMBLY_API_KEY;
    const appId = process.env.PREMBLY_APP_ID;

    if (!apiKey || !appId) {
      throw new InternalServerErrorException('Prembly credentials are not configured');
    }

    const payload = {
      rc_number: registrationNumber,
      company_type: companyType,
    };

    try {
      const response = await lastValueFrom(
        this.httpService.post(
          'https://api.prembly.com/kyb/v1/business-verification',
          payload,
          {
            headers: {
              'x-api-key': apiKey,
              'app-id': appId,
              'Content-Type': 'application/json',
            },
          },
        ),
      );

      return response.data;
    } catch (error: any) {
      throw new InternalServerErrorException(
        error.response?.data || error.message,
      );
    }
  }
}

