import { Controller, Post, Headers, Body, Req, UnauthorizedException, HttpCode, HttpStatus } from '@nestjs/common';
import * as crypto from 'crypto';
import { Request } from 'express';

@Controller('webhook')
export class WebhookController {
  @Post('prembly')
  @HttpCode(HttpStatus.OK)
  handlePremblyWebhook(
    @Headers('x-prembly-signature') signature: string,
    @Req() req: Request,
    @Body() body: any,
  ) {
    if (!signature) {
      throw new UnauthorizedException('Missing signature');
    }

    const secret = process.env.PREMBLY_WEBHOOK_SECRET || process.env.PREMBLY_API_KEY;
    if (!secret) {
      throw new UnauthorizedException('Webhook secret not configured');
    }

    // Since NestJS parses the body, we need the raw body to verify the signature properly.
    // However, if raw body is not available, we can stringify the parsed body.
    // For a robust solution, it's better to configure raw body parsing, but stringifying is a common fallback.
    const payload = req['rawBody'] ? req['rawBody'].toString('utf8') : JSON.stringify(body);

    const expectedSignature = crypto
      .createHmac('sha512', secret)
      .update(payload)
      .digest('hex');

    if (signature !== expectedSignature) {
      throw new UnauthorizedException('Invalid signature');
    }

    // Process the webhook payload (e.g., update database with verification status)
    console.log('Received valid Prembly webhook:', body);

    return { status: 'success' };
  }
}

